// USAGE EXAMPLES
// ============================================================================
/*

// 1. CREATE INSTANCE
final product = Product(
  id: 1,
  title: 'Laptop',
  price: 999.99,
  description: 'Gaming laptop',
  imageUrl: 'https://example.com/laptop.jpg',
);

// 2. COPY WITH MODIFICATIONS
final updatedProduct = product.copyWith(
  price: 899.99,
  stock: 10,
);

// 3. EQUALITY
print(product == updatedProduct); // false (price changed)

// 4. JSON SERIALIZATION
final json = product.toJson();
final fromJson = Product.fromJson(json);

// 5. PATTERN MATCHING (Union types)
// See ProductState below for union type example

*/

// ============================================================================
// Union Types (Sealed Classes) - Advanced freezed feature
// ============================================================================
// Represents different states of data loading
// Perfect for state management

@freezed
class ProductState with _$ProductState {
  const factory ProductState.initial() = _Initial;
  const factory ProductState.loading() = _Loading;
  const factory ProductState.success(List<Product> products) = _Success;
  const factory ProductState.error(String message) = _Error;
}

